#include <stdio.h>
#include <errno.h>

/* == EXEMPLE ===============================================
 * Afficher un message d'erreur pour EINVAL
 * errno est une variable globale mise à jour par le noyau.
 * perror(prefix) affiche: prefix: description de l'erreur
 * ========================================================= */
void example_errno(void) {
    errno = EINVAL;
    perror("Example EINVAL");
    printf("EINVAL=%d\n", EINVAL);
}
/* Resultat: Example EINVAL: Invalid argument */
